public static void returnFromElementEvent(RecId _recId)
{
    next returnFromElementEvent(_recId);

    if(ETGACFParameters::find().EnableIntercompanyTransactions == NoYes::Yes)
    {
        LedgerJournalTable ledgerjournalTable = LedgerJournalTable::findByRecId(_recId);

        if(ledgerjournalTable.ETGICSourceEntity)
        {
            changecompany(ledgerjournalTable.ETGICSourceEntity)
            {
                LedgerJournalTable ledgerJournalTableSource;

                select firstonly ledgerJournalTableSource
                where ledgerJournalTableSource.JournalNum == ledgerjournalTable.ETGSourceEntityJournalNum;

                if(ledgerJournalTableSource)
                {
                    try
                    {
                        SysEmailParameters _SysEmailParameters;

                        var builder = new SysMailerMessageBuilder();
                        select SMTPUserName from _SysEmailParameters;

                        if(_SysEmailParameters.SMTPUserName)
                        {
                            LedgerJournalName ledgerjournalnameloc;

                            select firstonly ledgerjournalnameloc
                            where ledgerjournalnameloc.Journalname == ledgerjournalTable.JournalName;

                            UserInfo userinfo;

                            select firstonly userinfo
                            where userinfo.id == ledgerJournalTableSource.CreatedBy;

                            if(userinfo)
                            {
                                builder.setFrom(_SysEmailParameters.SMTPUserName);
                                builder.addTo(userinfo.networkAlias);

                                builder.setSubject(strFmt("Journal rejected"));

                                builder.setBody(strFmt("Journal is rejected in %1  Journal number : %2  Source journal number : %3 Source journal entity : %4",ledgerJournalTableSource.ETGICDestinationentity,ledgerjournalTable.JournalNum,ledgerJournalTableSource.JournalNum,ledgerJournalTableSource.DataAreaId));

                                var message = builder.getMessage();

                                SysMailerFactory::getNonInteractiveMailer().sendNonInteractive(message);

                                Info("@ETG_New:EmailSuccess");
                            }
                        }

                    }
                    catch
                    {
                        return;
                    }

                }

            }
        }
    }

}

public static void requestChangeFromElementEvent(RecId _recId)
{
    LedgerJournalTable ledgerjournalTable = LedgerJournalTable::findByRecId(_recId);

    if(ledgerjournalTable.ETGICSourceEntity)
    {
        throw Error("@ETG_New:RequestChangeNotAllowed");
    }

    next requestChangeFromElementEvent(_recId);
}
